namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public Instructor Instructor { get; set; } = new();
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        var instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Dr. Chen specializes in distributed systems and cloud computing. She has published over 50 papers and received the ACM Distinguished Educator Award.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Wright", Title = "Associate Professor", Bio = "Dr. Wright's research focuses on machine learning and natural language processing. He previously worked at a major tech company for 10 years.", Email = "j.wright@university.edu" },
            new() { Id = 3, Name = "Dr. Maria Rodriguez", Title = "Professor", Bio = "Dr. Rodriguez is an expert in abstract algebra and number theory. She has mentored over 20 PhD students.", Email = "m.rodriguez@university.edu" },
            new() { Id = 4, Name = "Dr. Alan Foster", Title = "Assistant Professor", Bio = "Dr. Foster researches quantum mechanics and particle physics. He joined the department after completing postdoctoral work at CERN.", Email = "a.foster@university.edu" },
            new() { Id = 5, Name = "Dr. Emily Park", Title = "Professor", Bio = "Dr. Park is a scholar of Victorian literature and postcolonial studies. She has authored three books on 19th-century British novels.", Email = "e.park@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Kim", Title = "Associate Professor", Bio = "Dr. Kim specializes in modern American history with a focus on civil rights movements. He is a frequent contributor to historical journals.", Email = "r.kim@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control structures, functions, and basic data structures. No prior programming experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures & Algorithms", Description = "Advanced study of data structures including trees, graphs, and hash tables. Algorithm design and complexity analysis. Prerequisites: CS 101, CS 201.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[1], IsFeatured = true },
            new() { Id = 3, Code = "CS 450", Title = "Machine Learning", Description = "Introduction to machine learning concepts including supervised and unsupervised learning, neural networks, and model evaluation. Prerequisites: CS 301, MATH 202.", Credits = 3, Schedule = "Mon/Wed 2:00–3:30 PM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[1], IsFeatured = false },
            new() { Id = 4, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2], IsFeatured = true },
            new() { Id = 5, Code = "MATH 202", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and eigenvectors.", Credits = 3, Schedule = "Tue/Thu 1:00–2:30 PM", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2], IsFeatured = false },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to classical physics with laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:00 PM", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3], IsFeatured = false },
            new() { Id = 7, Code = "PHYS 310", Title = "Quantum Mechanics", Description = "Wave-particle duality, Schrödinger equation, quantum states, and measurement theory. Prerequisites: PHYS 201, MATH 301.", Credits = 3, Schedule = "Tue/Thu 9:00–10:30 AM", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3], IsFeatured = true },
            new() { Id = 8, Code = "ENG 101", Title = "College Writing", Description = "Develop critical reading and academic writing skills. Focus on argumentation, research methods, and clear prose.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4], IsFeatured = false },
            new() { Id = 9, Code = "ENG 350", Title = "Victorian Literature", Description = "Survey of major Victorian novels and poetry. Authors include Dickens, Brontë, Tennyson, and Eliot.", Credits = 3, Schedule = "Tue/Thu 3:00–4:30 PM", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4], IsFeatured = false },
            new() { Id = 10, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from antiquity to the early modern period.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", DepartmentId = 5, DepartmentName = "History", Instructor = instructors[5], IsFeatured = false },
            new() { Id = 11, Code = "HIST 320", Title = "Civil Rights in America", Description = "Examination of the civil rights movement from Reconstruction through the present day. Primary source analysis and historiographical debate.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:30 PM", DepartmentId = 5, DepartmentName = "History", Instructor = instructors[5], IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

