@page "/"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the course catalog. Browse departments, explore courses, and submit your enrollment request.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &middot; @course.DepartmentName</p>
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="departments/@dept.Id" class="btn btn-outline-primary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<UniversityCourseCatalog.Models.Course> featuredCourses = new();
    private List<UniversityCourseCatalog.Models.Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" class="form-control" placeholder="Search courses..." value="@Search" />
    </div>
    <div class="col-md-4">
        <select name="department" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(Department == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Any())
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.Instructor.Name</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No courses found matching your criteria.</p>
}

@code {
    [SupplyParameterFromQuery(Name = "search")]
    public string? Search { get; set; }

    [SupplyParameterFromQuery(Name = "department")]
    public int? Department { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = new();
    private List<UniversityCourseCatalog.Models.Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.SearchCourses(Search, Department);
    }
}

@page "/departments"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Departments</PageTitle>

<h1>Departments</h1>

<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h4 class="card-title">@dept.Name</h4>
                    <span class="badge bg-secondary mb-2">@dept.Code</span>
                    <p class="card-text">@dept.Description</p>
                    <a href="departments/@dept.Id" class="btn btn-primary">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<UniversityCourseCatalog.Models.Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
    }
}

@page "/departments/{Id:int}"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>@(department?.Name ?? "Department Not Found")</PageTitle>

@if (department is null)
{
    <h1>Department Not Found</h1>
    <p>The requested department could not be found.</p>
    <a href="departments" class="btn btn-primary">Back to Departments</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="departments">Departments</a></li>
            <li class="breadcrumb-item active">@department.Name</li>
        </ol>
    </nav>

    <h1>@department.Name (@department.Code)</h1>
    <p class="lead">@department.Description</p>

    <h2 class="mt-4">Courses</h2>

    @if (courses.Any())
    {
        <div class="list-group">
            @foreach (var course in courses)
            {
                <a href="courses/@course.Id" class="list-group-item list-group-item-action">
                    <div class="d-flex w-100 justify-content-between">
                        <h5 class="mb-1">@course.Code — @course.Title</h5>
                        <span class="badge bg-primary rounded-pill">@course.Credits cr</span>
                    </div>
                    <p class="mb-1">@course.Schedule</p>
                    <small class="text-muted">Instructor: @course.Instructor.Name</small>
                </a>
            }
        </div>
    }
    else
    {
        <p class="text-muted">No courses are currently offered in this department.</p>
    }
}

@code {
    [Parameter]
    public int Id { get; set; }

    private UniversityCourseCatalog.Models.Department? department;
    private List<UniversityCourseCatalog.Models.Course> courses = new();

    protected override void OnInitialized()
    {
        department = CatalogService.GetDepartment(Id);
        if (department is not null)
        {
            courses = CatalogService.GetCoursesByDepartment(Id);
        }
    }
}

