arguments.file_text:
@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit a request to enroll in a course. All fields are required.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Your enrollment request has been submitted successfully. You will receive a confirmation via your student email.</p>
        <hr />
        <a href="courses" class="btn btn-outline-success">Browse More Courses</a>
    </div>
}
else
{
    @if (error)
    {
        <div class="alert alert-danger">
            Please fill in all required fields and select a valid course.
        </div>
    }

    <form method="post" @formname="enrollment" class="col-md-8">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                   value="@Model.StudentName" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                   value="@Model.StudentId" required placeholder="e.g., STU-12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select class="form-select" id="courseId" name="Model.CourseId" required>
                <option value="0">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">
                        @course.Code — @course.Title (@course.Credits cr)
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm]
    public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = new();
    private bool submitted;
    private bool error;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();

        if (PreselectedCourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = PreselectedCourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        // Check if this is a form POST by seeing if the model has data
        if (!string.IsNullOrWhiteSpace(Model.StudentName) || !string.IsNullOrWhiteSpace(Model.StudentId))
        {
            if (CatalogService.SubmitEnrollmentRequest(Model))
            {
                submitted = true;
            }
            else
            {
                error = true;
            }
        }
    }
}

